import json
import urllib.parse
import urllib.request

data = _items[0]['json']

COLORS = [
    '#4C9BE8', '#E87B4C', '#4CE87B', '#E84C9B',
    '#9B4CE8', '#E8E84C', '#4CE8E8', '#E84C4C',
    '#9BE84C', '#4C4CE8', '#888888'
]

BASE_URL = "https://quickchart.io/chart?w=600&h=300&bkg=%231a1a2e&c="

def make_short_url(config):
    payload = json.dumps({"chart": config, "width": 600, "height": 300, "backgroundColor": "#1a1a2e"}).encode('utf-8')
    req = urllib.request.Request(
        "https://quickchart.io/chart/create",
        data=payload,
        headers={"Content-Type": "application/json"},
        method="POST"
    )
    with urllib.request.urlopen(req, timeout=10) as resp:
        result = json.loads(resp.read().decode())
        return result["url"]

def make_url(config):
    encoded = urllib.parse.quote(json.dumps(config))
    return BASE_URL + encoded

# --- Chart 1: Time per category (horizontal bar) ---
cats = list(data['by_category'].keys())
vals = [round(v / 3600, 2) for v in data['by_category'].values()]

chart_category = make_short_url({
    "type": "horizontalBar",
    "data": {
        "labels": cats,
        "datasets": [{
            "label": "Hours",
            "data": vals,
            "backgroundColor": COLORS[:len(cats)]
        }]
    },
    "options": {
        "legend": {"labels": {"fontColor": "white"}},
        "scales": {
            "xAxes": [{"ticks": {"fontColor": "white"}, "gridLines": {"color": "#333"}}],
            "yAxes": [{"ticks": {"fontColor": "white"}, "gridLines": {"color": "#333"}}]
        }
    }
})

# --- Chart 2: Daily activity bar ---
days = data['weekday_order']
by_day_short = {}
for k, v in data['by_day'].items():
    short = k.split(' ')[0]
    by_day_short[short] = by_day_short.get(short, 0) + v
day_vals = [round(by_day_short.get(d, 0) / 3600, 2) for d in days]

chart_daily = make_url({
    "type": "bar",
    "data": {
        "labels": days,
        "datasets": [{
            "label": "Hours",
            "data": day_vals,
            "backgroundColor": "#4C9BE8"
        }]
    },
    "options": {
        "legend": {"labels": {"fontColor": "white"}},
        "scales": {
            "xAxes": [{"ticks": {"fontColor": "white"}, "gridLines": {"color": "#333"}}],
            "yAxes": [{"ticks": {"fontColor": "white"}, "gridLines": {"color": "#333"}}]
        }
    }
})

# --- Chart 3: Top apps pie ---
app_labels = list(data['top_apps_pie'].keys())
app_vals = list(data['top_apps_pie'].values())
short_labels = [l[:35] + '...' if len(l) > 35 else l for l in app_labels]

chart_top_apps = make_url({
    "type": "pie",
    "data": {
        "labels": short_labels,
        "datasets": [{
            "data": app_vals,
            "backgroundColor": COLORS[:len(app_vals)]
        }]
    },
    "options": {
        "legend": {
            "position": "right",
            "labels": {"fontColor": "white", "fontSize": 10}
        }
    }
})

# --- Chart 4: Stacked bar category per day ---
categories = data['all_categories']
datasets = []
for i, cat in enumerate(categories):
    cat_vals = [round(data['stacked_by_category'].get(cat, {}).get(d, 0), 2) for d in days]
    datasets.append({
        "label": cat,
        "data": cat_vals,
        "backgroundColor": COLORS[i % len(COLORS)]
    })

chart_stacked = make_url({
    "type": "bar",
    "data": {
        "labels": days,
        "datasets": datasets
    },
    "options": {
        "scales": {
            "xAxes": [{"stacked": True, "ticks": {"fontColor": "white"}, "gridLines": {"color": "#333"}}],
            "yAxes": [{"stacked": True, "ticks": {"fontColor": "white"}, "gridLines": {"color": "#333"}}]
        },
        "legend": {"labels": {"fontColor": "white"}}
    }
})

# --- Chart 5: Active vs Idle doughnut ---
active_h = round(data['total_active_seconds'] / 3600, 2)
idle_h = round(data['total_idle_seconds'] / 3600, 2)
if active_h == 0 and idle_h == 0:
    idle_h = 0.01

chart_idle = make_url({
    "type": "doughnut",
    "data": {
        "labels": [f"Active {active_h}h", f"Idle {idle_h}h"],
        "datasets": [{
            "data": [active_h, idle_h],
            "backgroundColor": ["#4C9BE8", "#E84C4C"]
        }]
    },
    "options": {
        "legend": {
            "position": "bottom",
            "labels": {"fontColor": "white"}
        }
    }
})

# --- Chart 6: Heatmap (bubble chart) ---
heatmap_data = []
for entry in data['heatmap']:
    if entry['weekday'] in days:
        heatmap_data.append({
            "x": entry['hour'],
            "y": days.index(entry['weekday']),
            "r": min(20, max(3, int(entry['seconds'] / 60)))
        })

chart_heatmap = make_short_url({
    "type": "bubble",
    "data": {
        "datasets": [{
            "label": "Activity",
            "data": heatmap_data,
            "backgroundColor": "#4C9BE8"
        }]
    },
    "options": {
        "legend": {"labels": {"fontColor": "white"}},
        "scales": {
            "xAxes": [{
                "ticks": {"fontColor": "white", "min": 0, "max": 23, "stepSize": 1},
                "gridLines": {"color": "#333"},
                "scaleLabel": {"display": True, "labelString": "Hour of day", "fontColor": "white"}
            }],
            "yAxes": [{
                "ticks": {
                    "fontColor": "white",
                    "min": 0,
                    "max": 6,
                    "stepSize": 1
                },
                "gridLines": {"color": "#333"},
                "scaleLabel": {"display": True, "labelString": "Day", "fontColor": "white"}
            }]
        }
    }
})
return [{'json': {
    'chart_category': chart_category,
    'chart_daily': chart_daily,
    'chart_top_apps': chart_top_apps,
    'chart_stacked': chart_stacked,
    'chart_idle': chart_idle,
    'chart_heatmap': chart_heatmap,
    'total_active_seconds': data['total_active_seconds'],
    'total_idle_seconds': data['total_idle_seconds'],
    'by_category': data['by_category'],
    'weekday_order': data['weekday_order'],
    'all_categories': data['all_categories'],
}}]

